#!/usr/bin/env bash
# Dianping API - Zero-Dependency Installer
# Usage: curl -fsSL <URL>/install.sh | bash
#        curl -fsSL <URL>/install.sh | bash -s -- /custom/path
set -e

DIR="${1:-dianping-api}"
mkdir -p "$DIR/scripts"

echo "Installing SKILL.md..."
echo "" | base64 -d > "$DIR/SKILL.md"

echo "Installing scripts/dianping_api.py..."
echo "" | base64 -d > "$DIR/scripts/dianping_api.py"

echo "Installing scripts/dianping_login.py..."
echo "" | base64 -d > "$DIR/scripts/dianping_login.py"

chmod +x "$DIR/scripts/"*.py

echo ""
echo "Dianping API installed successfully!"
echo "  Directory: $DIR"
echo ""
echo "Zero dependencies - only Python 3 + curl (pre-installed)"
echo ""
echo "Quick start:"
echo "  1. Set cookies:"
echo "     python3 $DIR/scripts/dianping_login.py --set-cookies DPER DPLET"
echo "  2. Search:"
echo "     python3 $DIR/scripts/dianping_api.py search keyword"
echo "  3. Shop detail:"
echo "     python3 $DIR/scripts/dianping_api.py shop SHOP_ID"
echo "  4. Deals:"
echo "     python3 $DIR/scripts/dianping_api.py deals SHOP_ID"
echo ""
echo "Docs: cat $DIR/SKILL.md"
